// swift-ai-hub — Apache-2.0
// Snapshot fixtures for the @Generable / @Guide / @Tool / @Parameter macros
// using Point-Free's swift-macro-testing. Inline snapshots below are
// generated by re-running the suite with `record: .missing` and then locked
// in under `record: .never` so CI fails (rather than silently rewrites) on
// drift.
//
// Complements the existing SwiftSyntaxMacrosTestSupport-based tests; does
// not replace them. Matrix (per docs/09:36 audit-E):
//   1. @Generable struct (primitive properties)
//   2. @Generable struct with nested @Generable field ($ref / inline schema)
//   3. @Generable enum with associated values (regression for af92a6b)
//   4. @Guide(Regex) pattern propagation (regression for 91e2948)
//   5. @Tool simple (top-level with execute + nested Arguments)
//   6. @Tool + @Parameter (tool with @Parameter-marked Arguments field)
//
// Scope note: MacroTesting 0.6.x's `.macros(_:)` trait takes only
// `[String: Macro.Type]`; there's no public knob to declare the macro's
// `conformances:` list. Snapshots therefore capture the MemberMacro output
// (+ ExtensionMacro output that the macro itself emits via `extension`
// decl syntax, as @Tool does). @Generable's Codable/Generable extension
// conformances are validated behaviourally by GenerableCodableTests, not
// here.

#if os(macOS)
  import MacroTesting
  import Testing

  @testable import SwiftAIHubMacros

  @Suite(
    .macros(
      [
        "Generable": GenerableMacro.self,
        "Guide": GuideMacro.self,
        "Tool": ToolMacro.self,
        "Parameter": ParameterMacro.self,
      ],
      record: .never
    )
  )
  struct MacroSnapshotTests {

    // 1. @Generable struct — primitive properties.
    @Test func generableStructPrimitives() {
      assertMacro {
        """
        @Generable
        struct Person {
          @Guide(description: "Given name")
          var name: String
          var age: Int
        }
        """
      } expansion: {
        """
        struct Person {
          var name: String
          var age: Int

          private let _rawGeneratedContent: GeneratedContent

          nonisolated public init(name: String, age: Int) {
              self.name = name
                  self.age = age

              var properties: [String: GeneratedContent] = [:]
              properties["name"] = GeneratedContent(name)
                  properties["age"] = age.generatedContent

              self._rawGeneratedContent = GeneratedContent(
                  kind: .structure(
                      properties: properties,
                      orderedKeys: ["name", "age"]
                  )
              )
          }

          nonisolated public init(_ generatedContent: GeneratedContent) throws {
              struct MissingFieldKey: CodingKey {
                  var stringValue: String
                  var intValue: Int? {
                    nil
                  }
                  init(stringValue: String) {
                    self.stringValue = stringValue
                  }
                  init?(intValue: Int) {
                    nil
                  }
              }

              self._rawGeneratedContent = generatedContent

              guard case .structure(let properties, _) = generatedContent.kind else {
                  throw DecodingError.typeMismatch(
                      Person.self,
                      DecodingError.Context(codingPath: [], debugDescription: "Expected structure for Person")
                  )
              }

              if let value = properties["name"] {
              switch value.kind {
              case .null:
                  throw DecodingError.valueNotFound(
                      String.self,
                      DecodingError.Context(codingPath: [], debugDescription: "Required property 'name' was null")
                  )
              default:
                  self.name = try value.value(String.self)
              }
              } else {
              throw DecodingError.keyNotFound(
                  MissingFieldKey(stringValue: "name"),
                  DecodingError.Context(codingPath: [], debugDescription: "Missing required property 'name'")
              )
              }
                      if let value = properties["age"] {
              switch value.kind {
              case .null:
                  throw DecodingError.valueNotFound(
                      Int.self,
                      DecodingError.Context(codingPath: [], debugDescription: "Required property 'age' was null")
                  )
              default:
                  self.age = try value.value(Int.self)
              }
              } else {
              throw DecodingError.keyNotFound(
                  MissingFieldKey(stringValue: "age"),
                  DecodingError.Context(codingPath: [], debugDescription: "Missing required property 'age'")
              )
              }
          }

          nonisolated public var generatedContent: GeneratedContent {
              var properties: [String: GeneratedContent] = [:]
              properties["name"] = GeneratedContent(name)
                      properties["age"] = age.generatedContent

              return GeneratedContent(
                  kind: .structure(
                      properties: properties,
                      orderedKeys: ["name", "age"]
                  )
              )
          }

          nonisolated public static var generationSchema: GenerationSchema {
              return GenerationSchema(
                  type: Self.self,
                  description: "Generated Person",
                  properties: [
                      GenerationSchema.Property(
                          name: "name",
                          description: "Given name",
                          type: String.self,
                          guides: []
                      ),
                      GenerationSchema.Property(
                          name: "age",
                          description: nil,
                          type: Int.self,
                          guides: []
                      )
                  ]
              )
          }

          public struct PartiallyGenerated: Identifiable, Sendable, ConvertibleFromGeneratedContent {
              public var id: GenerationID

              public let name: String?
                  public let age: Int?

              private let rawContent: GeneratedContent

              public init(_ generatedContent: GeneratedContent) throws {
                  self.id = generatedContent.id ?? GenerationID()
                  self.rawContent = generatedContent

                  if case .structure(let properties, _) = generatedContent.kind {
                      self.name = try? properties["name"]?.value(String.self)
                      self.age = try? properties["age"]?.value(Int.self)
                  } else {
                      self.name = nil
                              self.age = nil
                  }
              }

              public var generatedContent: GeneratedContent {
                  return rawContent
              }
          }

          nonisolated public func asPartiallyGenerated() -> PartiallyGenerated {
              return try! PartiallyGenerated(_rawGeneratedContent)
          }

          nonisolated public var instructionsRepresentation: Instructions {
              return Instructions(self.generatedContent.jsonString)
          }

          nonisolated public var promptRepresentation: Prompt {
              return Prompt(self.generatedContent.jsonString)
          }
        }
        """
      }
    }

