    // 3. @Generable enum with associated values — regression fixture for
    // commit af92a6b (correct init/generatedContent/schema synthesis).
    @Test func generableEnumAssociatedValues() {
      assertMacro {
        """
        @Generable
        enum SearchFilter {
          case keyword(String)
          case dateRange(start: Double, end: Double)
          case bounded(Int)
        }
        """
      } expansion: {
        #"""
        enum SearchFilter {
          case keyword(String)
          case dateRange(start: Double, end: Double)
          case bounded(Int)

          nonisolated public init(_ generatedContent: GeneratedContent) throws {
              do {
                  guard case .structure(let properties, _) = generatedContent.kind else {
                      throw DecodingError.typeMismatch(
                          SearchFilter.self,
                          DecodingError.Context(codingPath: [], debugDescription: "Expected structure for enum SearchFilter")
                      )
                  }

                  guard case .string(let caseValue) = properties["case"]?.kind else {
                      struct Key: CodingKey {
                          var stringValue: String
                          var intValue: Int? {
                            nil
                          }
                          init(stringValue: String) {
                            self.stringValue = stringValue
                          }
                          init?(intValue: Int) {
                            nil
                          }
                      }
                      throw DecodingError.keyNotFound(
                          Key(stringValue: "case"),
                          DecodingError.Context(codingPath: [], debugDescription: "Missing 'case' property in enum data for SearchFilter")
                      )
                  }

                  let valueContent = properties["value"]

                  switch caseValue {
                  case "keyword":
              if let valueContent = valueContent,
                 case .string(let stringValue) = valueContent.kind {
                  self = .keyword(stringValue)
              } else {
                  self = .keyword("")
              }
                          case "dateRange":
              if let valueContent = valueContent {
                  guard case .structure(let valueProperties, _) = valueContent.kind else {
                      throw DecodingError.typeMismatch(
                          [String: Any].self,
                          DecodingError.Context(codingPath: [], debugDescription: "Expected structure for enum case 'dateRange' associated values")
                      )
                  }
                  let start = try valueProperties["start"]?.value(Double.self) ?? 0.0
                              let end = try valueProperties["end"]?.value(Double.self) ?? 0.0
                  self = .dateRange(start: start, end: end)
              } else {
                  throw DecodingError.valueNotFound(
                      [String: Any].self,
                      DecodingError.Context(codingPath: [], debugDescription: "Missing value data for enum case 'dateRange' with associated values")
                  )
              }
                          case "bounded":
              if let valueContent = valueContent {
                  let intValue = try valueContent.value(Int.self)
                  self = .bounded(intValue)
              } else {
                  self = .bounded(0)
              }
                  default:
                      throw DecodingError.dataCorrupted(
                          DecodingError.Context(codingPath: [], debugDescription: "Invalid enum case '\(caseValue)' for SearchFilter. Valid cases: [keyword, dateRange, bounded]")
                      )
                  }
              } catch {
                  guard case .string(let value) = generatedContent.kind else {
                      throw error
                  }
                  let trimmedValue = value.trimmingCharacters(in: .whitespacesAndNewlines)
                  switch trimmedValue {

                  default:
                      throw DecodingError.dataCorrupted(
                          DecodingError.Context(codingPath: [], debugDescription: "Invalid enum case '\(trimmedValue)' for SearchFilter. Valid cases: [keyword, dateRange, bounded]")
                      )
                  }
              }
          }

          nonisolated public var generatedContent: GeneratedContent {
              switch self {
              case .keyword(let value):
              return GeneratedContent(properties: [
                  "case": GeneratedContent("keyword"),
                  "value": value.generatedContent
              ])
                      case .dateRange(let start, let end):
              return GeneratedContent(properties: [
                  "case": GeneratedContent("dateRange"),
                  "value": GeneratedContent(properties: [
                      "start": start.generatedContent,
                                  "end": end.generatedContent
                  ])
              ])
                      case .bounded(let value):
              return GeneratedContent(properties: [
                  "case": GeneratedContent("bounded"),
                  "value": value.generatedContent
              ])
              }
          }

          nonisolated public static var generationSchema: GenerationSchema {
              let caseSchema = DynamicGenerationSchema(
                  name: "SearchFilter_Case",
                  anyOf: ["keyword", "dateRange", "bounded"]
              )
              let valueSchema = DynamicGenerationSchema(
                  name: "SearchFilter_Value",
                  anyOf: [DynamicGenerationSchema(type: String.self), DynamicGenerationSchema(name: "SearchFilter_dateRange_Payload", properties: [DynamicGenerationSchema.Property(name: "start", schema: DynamicGenerationSchema(type: Double.self)), DynamicGenerationSchema.Property(name: "end", schema: DynamicGenerationSchema(type: Double.self))]), DynamicGenerationSchema(type: Int.self)]
              )
              let root = DynamicGenerationSchema(
                  name: String(reflecting: Self.self),
                  description: "Generated SearchFilter",
                  properties: [
                      DynamicGenerationSchema.Property(
                          name: "case",
                          description: "Enum case identifier",
                          schema: caseSchema
                      ),
                      DynamicGenerationSchema.Property(
                          name: "value",
                          description: "Associated value data",
                          schema: valueSchema
                      )
                  ]
              )
              do {
                  return try GenerationSchema(root: root, dependencies: [])
              } catch {
                  fatalError("Failed to build generationSchema for SearchFilter: \(error)")
              }
          }

          nonisolated public func asPartiallyGenerated() -> SearchFilter {
              return self
          }

          nonisolated public var instructionsRepresentation: Instructions {
              return Instructions(self.generatedContent.jsonString)
          }

          nonisolated public var promptRepresentation: Prompt {
              return Prompt(self.generatedContent.jsonString)
          }
        }
        """#
      }
    }

    // 4. @Guide(Regex) — pattern literal must flow into schema (91e2948).
    @Test func generableGuideRegexPattern() {
      assertMacro {
        """
        @Generable
        struct Tagged {
          @Guide(/[A-Za-z]+/)
          var name: String

          @Guide(description: "hex color", /#[0-9A-Fa-f]{6}/)
          var color: String
        }
        """
      } expansion: {
        """
        struct Tagged {
          var name: String
          var color: String

          private let _rawGeneratedContent: GeneratedContent

          nonisolated public init(name: String, color: String) {
              self.name = name
                  self.color = color

              var properties: [String: GeneratedContent] = [:]
              properties["name"] = GeneratedContent(name)
                  properties["color"] = GeneratedContent(color)

              self._rawGeneratedContent = GeneratedContent(
                  kind: .structure(
                      properties: properties,
                      orderedKeys: ["name", "color"]
                  )
              )
          }

          nonisolated public init(_ generatedContent: GeneratedContent) throws {
              struct MissingFieldKey: CodingKey {
                  var stringValue: String
                  var intValue: Int? {
                    nil
                  }
                  init(stringValue: String) {
                    self.stringValue = stringValue
                  }
                  init?(intValue: Int) {
                    nil
                  }
              }

              self._rawGeneratedContent = generatedContent

              guard case .structure(let properties, _) = generatedContent.kind else {
                  throw DecodingError.typeMismatch(
                      Tagged.self,
                      DecodingError.Context(codingPath: [], debugDescription: "Expected structure for Tagged")
                  )
              }

              if let value = properties["name"] {
              switch value.kind {
              case .null:
                  throw DecodingError.valueNotFound(
                      String.self,
                      DecodingError.Context(codingPath: [], debugDescription: "Required property 'name' was null")
                  )
              default:
                  self.name = try value.value(String.self)
              }
              } else {
              throw DecodingError.keyNotFound(
                  MissingFieldKey(stringValue: "name"),
                  DecodingError.Context(codingPath: [], debugDescription: "Missing required property 'name'")
              )
              }
                      if let value = properties["color"] {
              switch value.kind {
              case .null:
                  throw DecodingError.valueNotFound(
                      String.self,
                      DecodingError.Context(codingPath: [], debugDescription: "Required property 'color' was null")
                  )
              default:
                  self.color = try value.value(String.self)
              }
              } else {
              throw DecodingError.keyNotFound(
                  MissingFieldKey(stringValue: "color"),
                  DecodingError.Context(codingPath: [], debugDescription: "Missing required property 'color'")
              )
              }
          }

          nonisolated public var generatedContent: GeneratedContent {
              var properties: [String: GeneratedContent] = [:]
              properties["name"] = GeneratedContent(name)
                      properties["color"] = GeneratedContent(color)

              return GeneratedContent(
                  kind: .structure(
                      properties: properties,
                      orderedKeys: ["name", "color"]
                  )
              )
          }

          nonisolated public static var generationSchema: GenerationSchema {
              return GenerationSchema(
                  type: Self.self,
                  description: "Generated Tagged",
                  properties: [
                      GenerationSchema.Property(
                          name: "name",
                          description: nil,
                          type: String.self,
                          guides: [.pattern("[A-Za-z]+")]
                      ),
                      GenerationSchema.Property(
                          name: "color",
                          description: "hex color",
                          type: String.self,
                          guides: [.pattern("#[0-9A-Fa-f]{6}")]
                      )
                  ]
              )
          }

          public struct PartiallyGenerated: Identifiable, Sendable, ConvertibleFromGeneratedContent {
              public var id: GenerationID

              public let name: String?
                  public let color: String?

              private let rawContent: GeneratedContent

              public init(_ generatedContent: GeneratedContent) throws {
                  self.id = generatedContent.id ?? GenerationID()
                  self.rawContent = generatedContent

                  if case .structure(let properties, _) = generatedContent.kind {
                      self.name = try? properties["name"]?.value(String.self)
                      self.color = try? properties["color"]?.value(String.self)
                  } else {
                      self.name = nil
                              self.color = nil
                  }
              }

              public var generatedContent: GeneratedContent {
                  return rawContent
              }
          }

          nonisolated public func asPartiallyGenerated() -> PartiallyGenerated {
              return try! PartiallyGenerated(_rawGeneratedContent)
          }

          nonisolated public var instructionsRepresentation: Instructions {
              return Instructions(self.generatedContent.jsonString)
