    // 5. @Tool simple — top-level tool with execute + nested Arguments.
    @Test func toolSimple() {
      assertMacro {
        """
        @Tool("Returns the current date/time.")
        struct GetCurrentDateTool {
          @Generable
          struct Arguments {
            @Guide(description: "IANA timezone identifier")
            var timezone: String
          }

          func execute(_ arguments: Arguments) async throws -> String {
            "2026-04-22T00:00:00 (\\(arguments.timezone))"
          }
        }
        """
      } expansion: {
        #"""
        struct GetCurrentDateTool {
          struct Arguments {
            var timezone: String

            private let _rawGeneratedContent: GeneratedContent

            nonisolated public init(timezone: String) {
                self.timezone = timezone

                var properties: [String: GeneratedContent] = [:]
                properties["timezone"] = GeneratedContent(timezone)

                self._rawGeneratedContent = GeneratedContent(
                    kind: .structure(
                        properties: properties,
                        orderedKeys: ["timezone"]
                    )
                )
            }

            nonisolated public init(_ generatedContent: GeneratedContent) throws {
                struct MissingFieldKey: CodingKey {
                    var stringValue: String
                    var intValue: Int? {
                      nil
                    }
                    init(stringValue: String) {
                      self.stringValue = stringValue
                    }
                    init?(intValue: Int) {
                      nil
                    }
                }

                self._rawGeneratedContent = generatedContent

                guard case .structure(let properties, _) = generatedContent.kind else {
                    throw DecodingError.typeMismatch(
                        Arguments.self,
                        DecodingError.Context(codingPath: [], debugDescription: "Expected structure for Arguments")
                    )
                }

                if let value = properties["timezone"] {
                switch value.kind {
                case .null:
                    throw DecodingError.valueNotFound(
                        String.self,
                        DecodingError.Context(codingPath: [], debugDescription: "Required property 'timezone' was null")
                    )
                default:
                    self.timezone = try value.value(String.self)
                }
                } else {
                throw DecodingError.keyNotFound(
                    MissingFieldKey(stringValue: "timezone"),
                    DecodingError.Context(codingPath: [], debugDescription: "Missing required property 'timezone'")
                )
                }
            }

            nonisolated public var generatedContent: GeneratedContent {
                var properties: [String: GeneratedContent] = [:]
                properties["timezone"] = GeneratedContent(timezone)

                return GeneratedContent(
                    kind: .structure(
                        properties: properties,
                        orderedKeys: ["timezone"]
                    )
                )
            }

            nonisolated public static var generationSchema: GenerationSchema {
                return GenerationSchema(
                    type: Self.self,
                    description: "Generated Arguments",
                    properties: [
                        GenerationSchema.Property(
